insert into public.evaluation_cycles (id, name, status, anon_min_responses, created_by)
insert into public.questions
  (cycle_id, code, text, text_cs, type, category, target_assignment_types, options, sort_order, is_required)
values
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'value_self', 'How valued and appreciated do you feel at work?', 'Jak oceňovaně a uznávaně se v práci cítíš?', 'multi_choice', 'value', array['self']::text[], '[{"value":4,"en":"I feel highly valued, trusted and appreciated by both my manager and the organization.","cs":"Cítím se velmi ceněný/á, mám důvěru a uznání jak od svého manažera, tak od firmy."},{"value":3,"en":"I feel respected, but valuable, meaningful recognition and appreciation from my manager and/or the company is rare.","cs":"Cítím respekt, ale skutečné, smysluplné uznání a ocenění od manažera a/nebo firmy je vzácné."},{"value":2,"en":"I feel rarely valued, but more often feel overlooked as neither my manager nor the company acknowledges my contributions.","cs":"Cítím se oceněný/á jen zřídka, častěji přehlížený/á – ani manažer, ani firma neuznávají můj přínos."},{"value":1,"en":"I don''t feel valued and appreciated by either my manager or the company.","cs":"Necítím se ceněný/á ani oceněný/á ze strany manažera ani firmy."}]'::jsonb, 1, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'value_manager', 'How would you assess this person''s value to the team and organization?', 'Jak hodnotíš přínos tohoto člověka pro tým a firmu?', 'multi_choice', 'value', array['downward']::text[], '[{"value":4,"en":"This employee is highly valued, trusted, and critical to the team and organization, consistently delivering value, their departure would be a severe loss, and keeping them is a priority.","cs":"Tento člověk je velmi ceněný, má důvěru a je pro tým a firmu klíčový, soustavně přináší hodnotu; jeho odchod by byl vážnou ztrátou a jeho udržení je priorita."},{"value":3,"en":"This employee is respected and reliable team member, brings solid value, meets performance goals, recognition is given, their departure would be a trouble and we don''t want to loose them.","cs":"Tento člověk je respektovaný a spolehlivý člen týmu, přináší solidní hodnotu, plní cíle, dostává uznání; jeho odchod by byl problém a nechceme o něj přijít."},{"value":2,"en":"This employee delivers limited value, inconsistent performance, and struggles to meet goals; their departure would be manageable, and I would not actively oppose or regret their exit.","cs":"Tento člověk přináší omezenou hodnotu, podává nekonzistentní výkon a má potíže plnit cíle; jeho odchod bychom zvládli a aktivně bych mu nebránil/a ani jej nelitoval/a."},{"value":1,"en":"This employee is not performing or bringing any added value in their role, their departure would be acceptable or even beneficial for the team.","cs":"Tento člověk ve své roli nepodává výkon ani nepřináší žádnou přidanou hodnotu; jeho odchod by byl přijatelný, nebo dokonce přínosný pro tým."}]'::jsonb, 2, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'nps_future', 'How much do you look forward to working with this colleague on future projects or tasks?', 'Jak moc se těšíš na spolupráci s ním/ní na dalších projektech nebo úkolech?', 'scale_10', 'engagement', array['upward','downward','peer']::text[], null, 3, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'text_strengths', 'What strengths or skills do you value most in this colleague, and how do they help you or the team succeed?', 'Kterých silných stránek nebo dovedností si na tomto kolegovi/kolegyni ceníš nejvíce a jak pomáhají tobě nebo týmu k úspěchu?', 'text', 'strengths', array['upward','downward','peer']::text[], null, 4, false),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'text_change', 'What is one thing this colleague could change in their communication, daily habits, or ways of working to help you and the team collaborate even better?', 'Co jednoho by mohl/a tento kolega/kolegyně změnit ve své komunikaci, každodenních návycích nebo způsobu práce, aby se ti a týmu spolupracovalo ještě lépe?', 'text', 'development', array['upward','downward','peer']::text[], null, 5, false),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_01', 'Shares relevant information in a timely manner without needing to be asked.', 'Sdílí relevantní informace včas, aniž by bylo potřeba se doptávat.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 10, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_02', 'When communicating with them, I know where I stand; they express themselves clearly and without unnecessary ambiguity.', 'V komunikaci s ním/ní vím, na čem jsem, vyjadřuje se jasně a bez zbytečných nejasností.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 11, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_03', 'Listens actively to others and takes their perspective into account, even when it differs from his/her own.', 'Aktivně naslouchá ostatním a bere jejich pohled v úvahu, i když se liší od jeho/jejího vlastního.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 12, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_04', 'Delivers results at the agreed-upon quality and by the promised deadline.', 'Dodává výstupy v dohodnuté kvalitě a ve slíbeném termínu.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 13, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_05', 'When encountering a problem that threatens the outcome, he/she lets others know in advance, not at the last minute.', 'Když narazí na problém ohrožující výsledek, dá o tom vědět dopředu, ne na poslední chvíli.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 14, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_06', 'Takes responsibility for the results of their work; when something goes wrong, they do not make excuses or shift blame onto others.', 'Přebírá odpovědnost za výsledky své práce, když se něco nepovede, nehledá výmluvy ani nepřesouvá zodpovědnost na ostatní.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 15, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_07', 'When encountering a problem, considers multiple options and proposes a specific solution, not just a description of the situation.', 'Když narazí na problém, přijde zpravidla s konkrétním návrhem řešení, ne jen s popisem situace.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 16, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_08', 'Contributes ideas and suggestions that provide real value to the team or project.', 'Přichází s nápady a návrhy, které mají reálný přínos pro tým nebo projekt.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 17, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_09', 'Helps others even beyond the scope of their own tasks.', 'Pomáhá ostatním i nad rámec vlastních úkolů.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 18, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_10', 'Responds to changes and unexpected situations flexibly, without unnecessary delay.', 'Reaguje na změny a nečekané situace pružně, bez zbytečného otálení.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 19, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_11', 'Accepts critical feedback objectively and actively works with it, striving to improve.', 'Přijímá kritickou zpětnou vazbu věcně a aktivně s ní pracuje, snaží se zlepšovat.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 20, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_12', 'Provides feedback to colleagues in a way that is both helpful and respectful.', 'Dává kolegům zpětnou vazbu způsobem, který je užitečný a zároveň respektující.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 21, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_13', 'Voices a problem or concern openly, even when others disagree.', 'Pojmenuje problém nebo výhradu nahlas, i když ostatní mají jiný názor.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 22, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_14', 'When things go wrong, faces the issue head-on and seeks solutions rather than excuses.', 'Když se něco nepovede, staví se k tomu čelem a hledá řešení místo výmluv.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 23, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_15', 'Puts the team''s success above personal recognition, shares credit and works together with others.', 'Staví úspěch týmu nad osobní zviditelnění, sdílí zásluhy a táhne za jeden provaz.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 24, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_16', 'Treats others with respect, contributes to a psychologically safe environment, and creates an atmosphere where people aren''t afraid to speak their minds or admit a mistake.', 'Jedná s respektem k druhým, přispívá k psychologicky bezpečnému prostředí, lidé se nebojí říct svůj názor nebo uznat chybu.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 25, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_17', 'This colleague acts and delivers consistently across different situations (workload or changing circumstances) and under pressure. Their behaviour is predictably positive.', 'Jedná a podává konzistentní výkony v různých situacích (ať už jde o pracovní vytížení nebo měnící se okolnosti) i pod tlakem. Jeho chování je v pozitivním smyslu předvídatelné.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 26, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'beh_18', 'Acts fairly and maintains high ethical standards.', 'Jedná spravedlivě a dodržuje vysoké etické standardy.', 'scale_5', 'behavioral', array['upward','downward','peer']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 27, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'mgr_19', 'I receive feedback from them that helps me grow, not just an evaluation, but specific guidance on what to improve.', 'Dostávám od něj/ní zpětnou vazbu, která mi pomáhá růst, nejen hodnocení, ale i konkrétní směr, co zlepšit.', 'scale_5', 'manager', array['upward']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 30, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'mgr_20', 'They communicate information and make decisions in a timely and clear manner; they do not prolong uncertainty through unnecessary delays or vagueness.', 'Předává informace a přijímá rozhodnutí včas a srozumitelně, neprodlužuje nejistotu zbytečným odkládáním nebo mlžením.', 'scale_5', 'manager', array['upward']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 31, true),
  ('cccccccc-cccc-cccc-cccc-cccccccccccc', 'mgr_21', 'They stand up for the team or an individual when needed, even against superiors or other teams.', 'Zastane se týmu nebo jednotlivce, když je to potřeba, i vůči nadřízeným nebo jiným týmům.', 'scale_5', 'manager', array['upward']::text[], '[{"value":5,"en":"Always / almost always","cs":"Vždy / téměř vždy"},{"value":4,"en":"Most of the time","cs":"Většinou"},{"value":3,"en":"Sometimes","cs":"Někdy"},{"value":2,"en":"Rarely","cs":"Zřídka"},{"value":1,"en":"Never / almost never","cs":"Nikdy / téměř nikdy"}]'::jsonb, 32, true)
